// El UPDATE anterior no devuelve filas.
// Este nodo recupera los datos del asset desde Get Asset
// y los pasa al siguiente nodo para que Read Image tenga el archivo.
const asset = $('Get Asset').first().json;
return [{ json: asset }];

const item = $input.first();
const bin = item.binary?.data;
if (!bin) throw new Error('No se encontró la imagen: ' + $('Restore Asset Data').first().json.archivo);

const assetId = $('Webhook').first().json.asset_id;
const mimeType = bin.mimeType || 'image/jpeg';
const base64 = bin.data;

const prompt = `Analiza esta imagen de joyería artesanal de resina. Responde ÚNICAMENTE con un JSON válido con esta estructura exacta, sin texto adicional ni bloques de código markdown:

{
  "tipo": "foto",
  "categoria": "pendientes" | "anillos" | "colgantes" | null,
  "colores": "colores principales de la pieza y flores",
  "materiales": "materiales detectados separados por coma (resina, flores secas, metal dorado...)",
  "caption_es": "caption atractivo en español para Instagram y web, máx 150 caracteres",
  "caption_en": "attractive English caption for Etsy listing, max 150 characters",
  "hashtags": "#resinajewelry #joyeriaresina #handmadejewelry #joyeriaartesanal #flowerjewelry (8-12 hashtags)",
  "plataformas_destino": "instagram,web,etsy" | "instagram,web" | "instagram",
  "descripcion": "descripción breve del producto en español"
}

Criterio para plataformas_destino:
- Incluir siempre instagram para fotografías
- Incluir web si la composición y calidad son buenas para catálogo
- Incluir etsy SOLO si el producto se ve claramente con fondo neutro/blanco y buena iluminación`;

const claudePayload = {
  model: 'claude-opus-4-5',
  max_tokens: 1024,
  messages: [{
    role: 'user',
    content: [
      {
        type: 'image',
        source: { type: 'base64', media_type: mimeType, data: base64 }
      },
      { type: 'text', text: prompt }
    ]
  }]
};

return [{ json: { assetId, claudePayload } }];

const response = $input.first().json;
const assetId = $('Webhook').first().json.asset_id;

try {
  const text = response.content?.[0]?.text;
  if (!text) throw new Error('Respuesta vacía de Claude');

  // Extraer JSON (eliminar posibles bloques markdown)
  const match = text.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No se encontró JSON en la respuesta de Claude');

  const parsed = JSON.parse(match[0]);

  return [{
    json: {
      assetId,
      success: true,
      tipo:                parsed.tipo                || 'foto',
      categoria:           parsed.categoria            || null,
      colores:             parsed.colores              || '',
      materiales:          parsed.materiales           || '',
      caption_es:          parsed.caption_es           || '',
      caption_en:          parsed.caption_en           || '',
      hashtags:            parsed.hashtags             || '',
      plataformas_destino: parsed.plataformas_destino  || 'instagram',
      descripcion:         parsed.descripcion          || ''
    }
  }];
} catch(e) {
  return [{
    json: { assetId, success: false, error: e.message }
  }];
}
